  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id                  Int       @id @default(autoincrement())\n  username            String    @unique\n  password            String\n  role                String // \"ADMIN\" or \"FACULTY\"\n  fullName            String?\n  email               String?   @unique\n  phoneNumber         String?\n  department          String? // Nullable for admin\n  designation         String? // e.g. \"Professor\", \"HOD\"\n  lastPasswordChange  DateTime? @default(now())\n  isDisabled          Boolean   @default(false)\n  forcePasswordChange Boolean   @default(false)\n  lastLogin           DateTime?\n\n  timetables        Timetable[]\n  facultyAbsences   FacultyAbsence[]\n  substitutions     Substitution[]\n  marksApproved     Marks[]             @relation(\"MarksApprover\")\n  takenAttendance   StudentAttendance[]\n  activityPerformed ActivityLog[]       @relation(\"PerformedBy\")\n\n  createdAt DateTime @default(now())\n}\n\nmodel ActivityLog {\n  id          Int      @id @default(autoincrement())\n  action      String // e.g. \"RESET_PASSWORD\", \"DISABLE_ACCOUNT\"\n  description String\n  performedBy Int\n  performer   User     @relation(\"PerformedBy\", fields: [performedBy], references: [id])\n  targetId    Int? // User ID of the faculty affected\n  timestamp   DateTime @default(now())\n}\n\nmodel Department {\n  id        Int      @id @default(autoincrement())\n  name      String   @unique\n  code      String?  @unique // e.g. \"CSE\", \"ECE\"\n  hodId     Int? // User ID of the HOD\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Student {\n  id             Int                 @id @default(autoincrement())\n  registerNumber String              @unique\n  name           String\n  department     String\n  year           Int // 1, 2, 3, 4\n  section        String // A, B, C\n  semester       Int\n  createdAt      DateTime            @default(now())\n  marks          Marks[]\n  attendance     StudentAttendance[]\n}\n\nmodel Timetable {\n  id         Int     @id @default(autoincrement())\n  department String\n  year       Int\n  semester   Int\n  section    String\n  day        String // MON, TUE, WED, THU, FRI\n  period     Int // 1 to 8\n  duration   Int     @default(1) // Number of periods (1 for regular class, 2-3 for labs)\n  type       String? // \"THEORY\", \"LAB\"\n\n  subjectName String?\n  facultyName String? // This could be a direct link to User model if faculty are users\n  room        String?\n\n  subjectId Int?\n  facultyId Int? // Link to User model for faculty\n\n  subject       Subject?       @relation(fields: [subjectId], references: [id])\n  faculty       User?          @relation(fields: [facultyId], references: [id])\n  substitutions Substitution[]\n\n  updatedAt DateTime @updatedAt\n\n  @@unique([department, year, semester, section, day, period])\n}\n\nmodel Subject {\n  id                 Int                 @id @default(autoincrement())\n  code               String              @unique\n  name               String\n  shortName          String?\n  department         String\n  semester           Int\n  marks              Marks[]\n  attendance         StudentAttendance[]\n  facultyAssignments FacultyAssignment[]\n  timetables         Timetable[]\n}\n\nmodel FacultyAssignment {\n  id        Int    @id @default(autoincrement())\n  facultyId Int\n  subjectId Int\n  section   String // A, B, C...\n\n  subject Subject @relation(fields: [subjectId], references: [id])\n  // We link to User (must be Faculty) manually or via logic, pure relation enforcing role is hard in SQL alone\n  // For simplicity we just store the ID, logic will verify it's a faculty\n}\n\nmodel Marks {\n  id              Int    @id @default(autoincrement())\n  studentId       Int\n  subjectId       Int\n  cia1_test       Float?\n  cia1_assignment Float?\n  cia1_attendance Float?\n\n  cia2_test       Float?\n  cia2_assignment Float?\n  cia2_attendance Float?\n\n  cia3_test       Float?\n  cia3_assignment Float?\n  cia3_attendance Float?\n\n  internal Float? // Calculated\n\n  // -- DEPRECATED (Keeping for backwards safety during migration, but logic will move to specifics) --\n  isLocked   Boolean @default(false)\n  isApproved Boolean @default(false)\n  // -----------------------------------------------------------------------------------------------\n\n  // Granular Locking & Approval\n  isLocked_cia1 Boolean @default(false)\n  isLocked_cia2 Boolean @default(false)\n  isLocked_cia3 Boolean @default(false)\n\n  isApproved_cia1 Boolean   @default(false)\n  isApproved_cia2 Boolean   @default(false)\n  isApproved_cia3 Boolean   @default(false)\n  approvedBy      Int?\n  approvedAt      DateTime?\n\n  updatedAt DateTime @updatedAt\n\n  student  Student @relation(fields: [studentId], references: [id])\n  subject  Subject @relation(fields: [subjectId], references: [id])\n  approver User?   @relation(\"MarksApprover\", fields: [approvedBy], references: [id])\n\n  @@unique([studentId, subjectId])\n}\n\nmodel FacultyAbsence {\n  id        Int      @id @default(autoincrement())\n  facultyId Int\n  date      String // ISO Date String YYYY-MM-DD\n  period    Int      @default(0) // 0 = Generic/All Day, >0 = Specific Period\n  reason    String?\n  createdAt DateTime @default(now())\n  faculty   User     @relation(fields: [facultyId], references: [id])\n\n  @@unique([facultyId, date, period])\n}\n\nmodel Substitution {\n  id                  Int      @id @default(autoincrement())\n  timetableId         Int // Link to original timetable slot\n  substituteFacultyId Int // Who is taking the class\n  date                String // ISO Date String YYYY-MM-DD\n  createdAt           DateTime @default(now())\n\n  timetable         Timetable @relation(fields: [timetableId], references: [id])\n  substituteFaculty User      @relation(fields: [substituteFacultyId], references: [id])\n\n  @@unique([timetableId, date])\n}\n\nmodel StudentAttendance {\n  id        Int      @id @default(autoincrement())\n  studentId Int\n  subjectId Int\n  facultyId Int // Who marked it\n  date      String // ISO Date String YYYY-MM-DD\n  period    Int      @default(0)\n  status    String // PRESENT, ABSENT, OD\n  createdAt DateTime @default(now())\n\n  student Student @relation(fields: [studentId], references: [id])\n  subject Subject @relation(fields: [subjectId], references: [id])\n  faculty User    @relation(fields: [facultyId], references: [id])\n\n  @@unique([studentId, subjectId, date, period]) // Prevent duplicate entries for same slot\n}\n",
